import numpy as np

def compute_brevity_penalty(c_len, r_len):
    if c_len > r_len:
        return 1.0
    return np.exp(1.0 - r_len / c_len) if c_len > 0 else 0.0

def run_practice():
    bp = compute_brevity_penalty(5, 10)
    assert np.allclose(bp, np.exp(-1.0))
    print('[PASS] Brevity penalty calculation matches.')

if __name__ == '__main__':
    run_practice()
